// ─── PRODUCTION IMPORTS ───────────────────────────────────────────────────────
// Supabase client — see lib/supabase.js
// In production: import { auth, users, posts, collections, trades } from '../lib/supabase.js';
// For now these are inlined below as a self-contained service layer with localStorage fallback.

// ─── API CLIENT ───────────────────────────────────────────────────────────────
// All AI calls go through the backend proxy (/api/ai/*) — never directly from frontend.
const API_URL = import.meta.env.VITE_API_URL || "";

const api = {
  _token: null,
  _setToken(t) { this._token = t; },
  _headers() {
    const h = { 'Content-Type': 'application/json' };
    if (this._token) h['Authorization'] = `Bearer ${this._token}`;
    return h;
  },
  async post(path, body) {
    try {
      const r = await fetch(`${API_URL}${path}`, { method:'POST', headers:this._headers(), body:JSON.stringify(body) });
      return r.ok ? r.json() : { error: `${r.status}`, mock: true };
    } catch { return { error:'Network error', mock: true }; }
  },
  async get(path) {
    try {
      const r = await fetch(`${API_URL}${path}`, { headers:this._headers() });
      return r.ok ? r.json() : { error: `${r.status}` };
    } catch { return { error:'Network error' }; }
  },
  async patch(path, body) {
    try {
      const r = await fetch(`${API_URL}${path}`, { method:'PATCH', headers:this._headers(), body:JSON.stringify(body) });
      return r.ok ? r.json() : { error: `${r.status}` };
    } catch { return { error:'Network error' }; }
  },
  async del(path) {
    try {
      const r = await fetch(`${API_URL}${path}`, { method:'DELETE', headers:this._headers() });
      return r.ok ? r.json() : { error: `${r.status}` };
    } catch { return { error:'Network error' }; }
  },
};

// ─── AUTH CONTEXT ─────────────────────────────────────────────────────────────
const AuthCtx = createContext({ user: null, session: null, loading: true, tokenReady: false, signOut: ()=>{} });
const useAuth = () => useContext(AuthCtx);

function normalizeProfile(user) {
  if (!user) return null;
  const groups = Array.isArray(user.favorite_groups) ? user.favorite_groups : Array.isArray(user.fandoms) ? user.fandoms : [];
  const handle = user.handle || user.username || user.name || user.stanName || "";
  const backstageName = user.backstage_name || user.display_name || user.displayName || user.name || user.stanName || user.username || "";
  const complete = Boolean((backstageName || user.display_name) && handle);
  return {
    ...user,
    handle,
    username:user.username || handle,
    backstage_name:backstageName,
    display_name:user.display_name || backstageName,
    favorite_groups:groups,
    fandoms:groups,
    bias:user.bias || "",
    bias_wrecker:user.bias_wrecker || user.biasWrecker || "",
    onboarding_complete:user.onboarding_complete === true || complete,
    profile_complete:user.profile_complete === true || complete,
  };
}

// ─── VIP HELPER ──────────────────────────────────────────────────────────────
// Single source of truth for VIP access. Handles two sources:
//   1. Paid VIP — set by Stripe webhook (user.is_vip === true)
//   2. Comped VIP — admin-granted (user.vip_source === "comped")
//      vip_expires_at: null = permanent, ISO string = time-limited
// Both sources unlock identical VIP features. Stripe is not bypassed for paid.
function isVipActive(user) {
  if (!user) return false;
  if (user.vip_active === true) return true;
  if (user.is_vip === true) return true;
  if (user.vip_source === "founder" || user.vip_source === "stripe") return true;
  if (user.vip_source === "comped") {
    if (!user.vip_expires_at) return true;
    return new Date(user.vip_expires_at) > new Date();
  }
  return false;
}

function hasVipEntitlement(user) {
  return isVipActive(user) || user?.vip_source === "founder" || user?.vip_source === "stripe";
}

function isFounderVip(user) {
  return user?.vip_source === "founder" || user?.plan === "founder";
}

const onboardingCompleteKey = userId => `backstage_onboarding_complete_${userId}`;
const vipCacheKey = userId => `backstage_is_vip_${userId}`;

function hasCompletedOnboarding(user) {
  if (!user) return false;
  if (user.onboarding_complete === true || user.profile_complete === true || user.onboarding_skipped === true) return true;
  if (!user.id) return false;
  if (ls.get(onboardingCompleteKey(user.id), false)) return true;
  const cachedUserId = ls.get("backstage_session")?.user?.id;
  return cachedUserId === user.id && ls.get("backstage_onboarding_complete", false) === true;
}

function markOnboardingComplete(user) {
  if (user?.id) ls.set(onboardingCompleteKey(user.id), true);
  ls.set("backstage_onboarding_complete", true);
}

function getCachedVip(user) {
  if (!user?.id) return false;
  if (ls.get(vipCacheKey(user.id), false) === true) return true;
  const cachedUserId = ls.get("backstage_session")?.user?.id;
  return cachedUserId === user.id && ls.get("backstage_is_vip", false) === true;
}

function setCachedVip(user, active) {
  if (user?.id) ls.set(vipCacheKey(user.id), active);
  ls.set("backstage_is_vip", active);
}

function isProfileComplete(user) {
  const profile = normalizeProfile(user);
  return Boolean(
    hasCompletedOnboarding(profile) ||
    ((profile?.display_name || profile?.backstage_name || profile?.username) &&
      (profile?.handle || profile?.username))
  );
}

function canEnterApp(user) {
  return hasCompletedOnboarding(user) || isProfileComplete(user);
}

function mergeStoredProfile(localProfile, remoteProfile, fallbackProfile = null) {
  const local = normalizeProfile(localProfile);
  const remote = normalizeProfile(remoteProfile);
  const fallback = normalizeProfile(fallbackProfile);
  if (canEnterApp(local) && !canEnterApp(remote)) {
    // Local profile has richer onboarding data (fandoms, handle) — prefer it.
    // BUT: VIP/payment fields are backend-authoritative. Always take them from
    // the remote (public.users SELECT *) so stale localStorage never hides
    // a paid VIP status. Only patch when remote is available.
    if (remote) {
      return normalizeProfile({
        ...local,
        is_vip:            remote.is_vip,
        vip_source:        remote.vip_source,
        vip_expires_at:    remote.vip_expires_at,
        vip_since:         remote.vip_since,
        stripe_customer_id: remote.stripe_customer_id,
      });
    }
    return local;
  }
  const merged = normalizeProfile({ ...(fallback || {}), ...(local || {}), ...(remote || {}) });
  if (canEnterApp(local) && !canEnterApp(merged)) return local;
  return merged;
}

// ─── SUPABASE CONFIG (inline — replace with lib/supabase.js import in production) ──
const RAW_SUPABASE_URL = import.meta.env.VITE_SUPABASE_URL || "";
const RAW_SUPABASE_ANON = import.meta.env.VITE_SUPABASE_ANON_KEY || "";

function stripWrappingQuotes(value) {
  const trimmed = String(value || "").trim();
  const pairs = [["'", "'"], ['"', '"'], ["`", "`"], ["“", "”"], ["‘", "’"]];
  const pair = pairs.find(([open, close]) => trimmed.startsWith(open) && trimmed.endsWith(close));
  return pair ? trimmed.slice(1, -1).trim() : trimmed;
}

function inspectSupabaseEnv(rawUrl, rawAnon) {
  const url = stripWrappingQuotes(rawUrl);
  const anon = stripWrappingQuotes(rawAnon);
  const anonRawTrimmed = String(rawAnon || "").trim();
  const anonChecks = {
    hasWhitespace: /\s/.test(anonRawTrimmed),
    hasNewline: /[\r\n]/.test(anonRawTrimmed),
    hasSmartQuotes: /[“”‘’]/.test(anonRawTrimmed),
    hasNonAscii: /[^\x00-\x7F]/.test(anonRawTrimmed),
  };
  const issues = [];
  let host = null;

  if (url) {
    try {
      const parsed = new URL(url);
      host = parsed.host;
      if (parsed.pathname.includes("/rest/v1") || parsed.pathname.includes("/auth/v1")) {
        issues.push("VITE_SUPABASE_URL must be the project URL only, without /rest/v1 or /auth/v1.");
      }
    } catch {
      issues.push("VITE_SUPABASE_URL is not a valid URL.");
    }
  }

  if (anon && (/\s/.test(anon) || /[^\x00-\x7F]/.test(anon))) {
    issues.push("VITE_SUPABASE_ANON_KEY contains whitespace, newlines, smart quotes, or non-ASCII characters.");
  }

  console.info("[launch:supabase-env]", {
    hasUrl: Boolean(url),
    urlHost: host,
    hasAnonKey: Boolean(anon),
    anonKeyLength: anon.length,
    anonKeyHasWhitespace: anonChecks.hasWhitespace,
    anonKeyHasNewline: anonChecks.hasNewline,
    anonKeyHasSmartQuotes: anonChecks.hasSmartQuotes,
    anonKeyHasNonAscii: anonChecks.hasNonAscii,
    anonKeyPrefix: anon.slice(0, 8),
  });

  return { url, anon, issues };
}

const SUPABASE_ENV = inspectSupabaseEnv(RAW_SUPABASE_URL, RAW_SUPABASE_ANON);
const SUPABASE_URL = SUPABASE_ENV.url;
const SUPABASE_ANON = SUPABASE_ENV.anon;
const SUPABASE_CONFIG_ERROR = SUPABASE_ENV.issues.length ? "Supabase configuration issue. Check VITE_SUPABASE_URL and VITE_SUPABASE_ANON_KEY." : "";
if (SUPABASE_CONFIG_ERROR) console.error(SUPABASE_CONFIG_ERROR, SUPABASE_ENV.issues);
const MOCK_AUTH = !SUPABASE_URL || !SUPABASE_ANON || Boolean(SUPABASE_CONFIG_ERROR);


let _supabase = null;
if (!MOCK_AUTH) {
  _supabase = createClient(SUPABASE_URL, SUPABASE_ANON, {
    // Use a separate key so Supabase auth tokens never overwrite the app's user profile in localStorage
    auth: { persistSession:true, storageKey:'backstage_supabase_auth', autoRefreshToken:true },
  });
}

// ─── AUTH PROVIDER ────────────────────────────────────────────────────────────
function AuthProvider({ children }) {
  const [user, setUser]           = useState(null);
  const [session, setSession]     = useState(null);
  const [loading, setLoading]     = useState(true);
  const [tokenReady, setTokenReady] = useState(false);

  useEffect(() => {
    // Boot: check cached session first
    const cached = ls.get('backstage_session');
    if (cached?.user) { setUser(cached.user); setLoading(false); }

    if (MOCK_AUTH) {
      // Mock mode: stay logged in if localStorage session exists
      setTokenReady(true);
      setLoading(false);
      return;
    }

    // Real Supabase session
    if (_supabase) {
      _supabase.auth.getSession().then(({ data }) => {
        setSession(data.session || null);
        if (data.session) {
          const u = data.session.user;
          const fallback = { id:u.id, email:u.email, username:u.email.split('@')[0], fandoms:[], bias:'', is_vip:false };
          api._setToken(data.session.access_token);
          setTokenReady(true);
          api.get('/api/users/me').then(remote=>{
            const profile = mergeStoredProfile(ls.get(`backstage_profile_${u.id}`), remote?.id ? remote : null, fallback);
            setUser(profile);
            ls.set('backstage_session', { user: profile });
            if (profile?.id) ls.set(`backstage_profile_${profile.id}`, profile);
          }).catch(()=>{
            const profile = mergeStoredProfile(ls.get(`backstage_profile_${u.id}`), null, fallback);
            setUser(profile);
            ls.set('backstage_session', { user: profile });
            if (profile?.id) ls.set(`backstage_profile_${profile.id}`, profile);
          }).finally(()=>setLoading(false));
          return;
        }
        setLoading(false);
      });

      const { data: { subscription } } = _supabase.auth.onAuthStateChange(async (event, session) => {
        setSession(session || null);
        if (session) {
          api._setToken(session.access_token);
          setTokenReady(true);
          const fallback = { id:session.user.id, email:session.user.email, username:session.user.email.split('@')[0], fandoms:[], bias:'', is_vip:false };
          const profile = await api.get('/api/users/me').catch(() => null);
          const u = mergeStoredProfile(ls.get(`backstage_profile_${session.user.id}`), profile?.id ? profile : null, fallback);
          setUser(u);
          ls.set('backstage_session', { user: u });
          if (u.id) ls.set(`backstage_profile_${u.id}`, u);
        } else {
          api._setToken(null);
          setTokenReady(false);
          setUser(null);
          ls.del('backstage_session');
        }
      });
      return () => subscription.unsubscribe();
    }
  }, []);

  const signOut = async () => {
    setUser(null);
    setSession(null);
    setTokenReady(false);
    ls.del('backstage_session');
    ls.del('backstage_is_vip');
    if (_supabase) await _supabase.auth.signOut();
  };

  return (
    <AuthCtx.Provider value={{ user, session, loading, tokenReady, signOut }}>
      {children}
    </AuthCtx.Provider>
  );
}


