// ─── FCM / Push Notification Helper ──────────────────────────────────────────
//
// CURRENT STATE (in-app only):
//   In-app notifications work via backstage_notif_inbox localStorage.
//   Deep-link routing is implemented (NotificationCenter.handleNotifTap).
//   This function requests browser permission but generates a MOCK token.
//   No real Firebase SDK is imported — device push is not active.
//
// TO ENABLE REAL DEVICE/BROWSER PUSH:
//   1. Create a Firebase project → enable Cloud Messaging.
//   2. Add VITE_FIREBASE_* env vars (see .env.example) to initialize Firebase.
//   3. Add VITE_FIREBASE_VAPID_KEY — the VAPID key the browser uses to register.
//   4. Create public/firebase-messaging-sw.js (service worker for background push).
//   5. Use firebase/messaging → getToken({ vapidKey: VITE_FIREBASE_VAPID_KEY })
//      instead of the mock token below.
//   6. Backend FIREBASE_PROJECT_ID + FIREBASE_CLIENT_EMAIL + FIREBASE_PRIVATE_KEY
//      enable Firebase Admin SDK to send via FCM HTTP v1 API.
//   7. Push payload should include `data.targetModal` or `data.targetTab` so
//      the notification click can deep-link into the correct Backstage screen.
//
// STATUS CHECKLIST:
//   ✅ Browser permission request
//   ✅ /api/save-token backend route
//   ✅ In-app notification routing (handleNotifTap)
//   ❌ firebase-messaging-sw.js (not created)
//   ❌ Firebase SDK import (not installed)
//   ❌ Real FCM token from getToken()
//   ❌ /api/send-notification wired to Firebase Admin SDK
//   ❌ Firebase env vars configured
// ─────────────────────────────────────────────────────────────────────────────
async function requestNotificationPermission(userId) {
  if (!("Notification" in window) || !("serviceWorker" in navigator)) return null;
  const permission = await Notification.requestPermission();
  if (permission !== "granted") return null;

  const FB_API_KEY    = import.meta.env.VITE_FIREBASE_API_KEY;
  const FB_PROJECT_ID = import.meta.env.VITE_FIREBASE_PROJECT_ID;
  const FB_VAPID      = import.meta.env.VITE_FIREBASE_VAPID_KEY;

  if (FB_API_KEY && FB_PROJECT_ID && FB_VAPID) {
    try {
      const { initializeApp, getApps } = await import('firebase/app');
      const { getMessaging, getToken }  = await import('firebase/messaging');
      const config = {
        apiKey:            FB_API_KEY,
        authDomain:        import.meta.env.VITE_FIREBASE_AUTH_DOMAIN,
        projectId:         FB_PROJECT_ID,
        messagingSenderId: import.meta.env.VITE_FIREBASE_MESSAGING_SENDER_ID,
        appId:             import.meta.env.VITE_FIREBASE_APP_ID,
      };
      const firebaseApp = getApps().length ? getApps()[0] : initializeApp(config);
      const messaging   = getMessaging(firebaseApp);
      const reg = await navigator.serviceWorker.register('/firebase-messaging-sw.js');
      // Send config to SW so it can handle background messages
      const sw = reg.active || reg.waiting || reg.installing;
      if (sw) sw.postMessage({ type: 'FIREBASE_CONFIG', config });
      await navigator.serviceWorker.ready;
      const token = await getToken(messaging, { vapidKey: FB_VAPID, serviceWorkerRegistration: reg });
      if (token) {
        await api.post('/api/save-token', { token, userId, platform: 'web' });
        return token;
      }
    } catch (err) {
      console.warn('[FCM] getToken failed:', err?.message);
    }
  }

  // Fallback: mock token (in-app notifications still work, no real device push)
  const mockToken = `mock-fcm-${userId}-${Date.now()}`;
  await api.post('/api/save-token', { token: mockToken, userId }).catch(()=>{});
  return mockToken;
}

// ═══════════════════════════════════════════════════════════════════════════════
// PHASE 5 — VIRALITY ENGINE COMPONENTS
// ═══════════════════════════════════════════════════════════════════════════════

// ─── INVITE FRIENDS / REFERRAL HUB ────────────────────────────────────────────
// POST /api/referrals/invite | GET /api/referrals/:userId | POST /api/referrals/claim
// POST /api/circle/request | GET /api/circle/:userId | POST /api/circle/accept
function InvitePage({ onBack, user, onNotif, isVip, onUpgrade, go }) {
  const [tab, setTab] = useState("find");
  const [copied, setCopied] = useState(false);
  const [showReward, setShowReward] = useState(false);
  const [referralCode, setReferralCode] = useState("");
  const [referralUrl, setReferralUrl] = useState("");
  const [referralStats, setReferralStats] = useState({
    converted_count:0,
    pending_count:0,
    rewards:[],
    milestones:REFERRAL_MILESTONES.map(m=>({ ...m, unlocked:false })),
  });
  const [referralSetupRequired, setReferralSetupRequired] = useState(false);

  // ── Social search state ───────────────────────────────────────────────────
  const [searchQ, setSearchQ] = useState("");
  const [searchFocused, setSearchFocused] = useState(false);
  const [userStatuses, setUserStatuses] = useState(()=>ls.get("backstage_circle_statuses",{}));
  const [circle, setCircle] = useState(()=>ls.get("backstage_circle",[]));
  const [pendingReqs, setPendingReqs] = useState(()=>ls.get("backstage_friend_requests",[]));
  // API search state
  const [searching, setSearching] = useState(false);
  const [apiResults, setApiResults] = useState([]);
  const [suggestedFans, setSuggestedFans] = useState([]);

  const fallbackCode = `BACKSTAGE-${(user?.username||user?.name||"FAN").toUpperCase().replace(/[^A-Z0-9]/g,"").slice(0,8)||"FAN"}-LOCAL`;
  const myCode = referralCode || fallbackCode;
  const myLink = referralUrl || `https://backstagefanverse.com/?ref=${encodeURIComponent(myCode)}`;
  const converted = referralStats.converted_count || 0;
  const nextMilestone = REFERRAL_MILESTONES.find(m=>m.count>converted)||REFERRAL_MILESTONES[REFERRAL_MILESTONES.length-1];

  // Normalize an API user card to the local card shape expected by the UI
  const normalizeUserCard = (u) => ({
    id: u.id,
    username: u.handle || u.username || '',
    displayName: u.display_name || u.backstage_name || u.handle || 'Backstage fan',
    avatar: (u.display_name || u.handle || u.username || 'B').slice(0,1).toUpperCase(),
    color: C.accent,
    fandoms: u.fandoms || u.favorite_groups || [],
    city: u.city || 'Backstage',
    concertContext: u.concert_context || '',
    bio: u.bio || `${u.display_name || u.handle || 'Fan'} is on Backstage`,
    emailPrefix: '',
    status: 'none',
  });

  // Debounced API search — fires when query hits 2+ chars
  useEffect(() => {
    const raw = searchQ.trim();
    const q = raw.replace(/^@/, '').toLowerCase();
    if (q.length < 2) { setApiResults([]); setSearching(false); return; }
    setSearching(true);
    const t = setTimeout(async () => {
      try {
        const d = await api.get(`/api/users/search?q=${encodeURIComponent(raw)}`);
        setApiResults(d?.users || []);
      } catch { setApiResults([]); }
      finally { setSearching(false); }
    }, 350);
    return () => clearTimeout(t);
  }, [searchQ]);

  // Load suggested fans once on mount
  useEffect(() => {
    api.get('/api/friends/suggested').then(d => {
      if (d?.users?.length > 0) setSuggestedFans(d.users.map(normalizeUserCard));
    }).catch(() => {});
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  useEffect(() => {
    let alive = true;
    api.get('/api/referrals/code').then(d => {
      if (!alive) return;
      setReferralSetupRequired(false);
      setReferralCode(d?.code || "");
      setReferralUrl(d?.invite_url || d?.url || "");
    }).catch(err => {
      if (!alive) return;
      setReferralSetupRequired(err?.status === 503);
    });
    api.get('/api/referrals/stats').then(d => {
      if (!alive) return;
      setReferralSetupRequired(false);
      setReferralStats({
        converted_count: Number(d?.converted_count || 0),
        pending_count: Number(d?.pending_count || 0),
        rewards: Array.isArray(d?.rewards) ? d.rewards : [],
        milestones: Array.isArray(d?.milestones) ? d.milestones : REFERRAL_MILESTONES.map(m => ({ ...m, unlocked:false })),
      });
    }).catch(err => {
      if (!alive) return;
      setReferralSetupRequired(err?.status === 503);
    });
    api.get('/api/circle').then(d => {
      if (!alive) return;
      const members = Array.isArray(d?.members) ? d.members.map(m => ({
        id:m.id,
        profileId:m.id,
        name:`@${m.handle || m.username || "fan"}`,
        displayName:m.display_name || m.backstage_name || m.handle || "Backstage fan",
        avatar:(m.display_name || m.handle || "B").slice(0,1).toUpperCase(),
        color:C.accent,
        type:"moot",
        groups:m.favorite_groups || m.fandoms || [],
        trust:5.0,
        concerts:0,
        status:"accepted",
        realProfile:true,
      })) : [];
      setCircle(members);
      ls.set("backstage_circle", members);
    }).catch(() => {});
    return () => { alive = false; };
  }, []);

  const copyLink = () => {
    navigator.clipboard?.writeText(myLink).catch(()=>{});
    setCopied(true); setTimeout(()=>setCopied(false),2000);
    onNotif({title:"Link copied! 🔗",body:"Share it with your crew.",icon:"🔗",color:C.mint});
  };

  const simulateInvite = () => {
    copyLink();
    setShowReward(true); setTimeout(()=>setShowReward(false),3500);
    onNotif({title:"Invite link ready",body:"Rewards unlock after your friend creates a confirmed Backstage account.",icon:"link",color:C.accent});
  };

  // ── Social: send crew invite / circle request ─────────────────────────────
  const sendRequest = async (fu) => {
    const next = {...userStatuses, [fu.id]:"sent"};
    setUserStatuses(next); ls.set("backstage_circle_statuses", next);
    const reqEntry = { id:`req-${Date.now()}`, userId:fu.id, username:fu.username, displayName:fu.displayName, avatar:fu.avatar, color:fu.color||C.accent, fandoms:fu.fandoms, concertContext:fu.concertContext, sentAt:Date.now() };
    const reqs = [reqEntry, ...pendingReqs];
    setPendingReqs(reqs); ls.set("backstage_friend_requests", reqs);
    // Best-effort backend sync — localStorage is the source of truth
    try {
      await api.post('/api/circle/request', { targetUserId: fu.id });
    } catch {
      onNotif({title:"Request saved locally",body:"Backstage will sync it after the social tables are installed.",icon:"link",color:C.lavender});
      return;
    }
    onNotif({title:`Circle invite sent to @${fu.username} ✦`,body:"They'll see your invite in their notifications.",icon:"💜",color:C.lavender});
  };

  const cancelRequest = (fu) => {
    const next = {...userStatuses, [fu.id]:"none"};
    setUserStatuses(next); ls.set("backstage_circle_statuses", next);
    const reqs = pendingReqs.filter(r=>r.userId!==fu.id);
    setPendingReqs(reqs); ls.set("backstage_friend_requests", reqs);
  };

  const acceptRequest = (fu) => {
    const next = {...userStatuses, [fu.id]:"accepted"};
    setUserStatuses(next); ls.set("backstage_circle_statuses", next);
    const member = { id:fu.id, name:`@${fu.username}`, avatar:fu.avatar, color:fu.color, type:"moot", groups:fu.fandoms, trust:5.0, concerts:0, status:"accepted" };
    const nextCircle = [member, ...circle.filter(c=>c.id!==fu.id)];
    setCircle(nextCircle); ls.set("backstage_circle", nextCircle);
    // Also persist to backstage_friends so MyCircleSection picks it up
    const friends = ls.get("backstage_friends", MOCK_FRIENDS);
    if(!friends.find(f=>f.id===fu.id)) ls.set("backstage_friends", [member,...friends]);
    // Add accepted notification
    const inbox = ls.get("backstage_notif_inbox", []);
    ls.set("backstage_notif_inbox", [{ id:`nf-acc-${Date.now()}`, type:"accepted", icon:"🌟", title:"Circle accepted", body:`@${fu.username} is now in your Circle ✦`, color:C.mint, time:"Just now", read:false },...inbox]);
    onNotif({title:`@${fu.username} joined your Circle ✦`,body:"In Your Circle now.",icon:"✦",color:C.mint});
  };

  const declineRequest = (fu) => {
    const next = {...userStatuses, [fu.id]:"declined"};
    setUserStatuses(next); ls.set("backstage_circle_statuses", next);
  };

  const getStatus = (fu) => userStatuses[fu.id] || fu.status || "none";

  // ── Search ────────────────────────────────────────────────────────────────
  // Normalize the query: strip @, lowercase, collapse whitespace
  const q = searchQ.trim().replace(/^@/, '').toLowerCase();
  const localProfiles = (() => {
    try {
      return Object.keys(localStorage)
        .filter(k=>k.startsWith("backstage_profile_"))
        .map(k=>normalizeProfile(ls.get(k)))
        .filter(p=>p?.id && p.id!==user?.id && canEnterApp(p))
        .map(p=>({
          id:p.id, username:p.handle||p.username||'', displayName:p.display_name || p.backstage_name || p.handle,
          avatar:(p.display_name || p.handle || "F").slice(0,1).toUpperCase(), color:C.accent,
          fandoms:p.favorite_groups || [], city:p.city || "Backstage", concertContext:"Signed-up fan",
          bio:`${p.display_name || p.handle} is on Backstage`, emailPrefix:p.email?.split("@")[0] || "",
        }));
    } catch { return []; }
  })();
  const searchableUsers = suggestedFans.length > 0 ? suggestedFans : localProfiles;

  // Build the displayed results list:
  // q >= 2 chars → API results merged with any local-only profiles not in API set
  // q == 1 char  → local prefix match (instant, no API)
  // q == 0       → suggested fans (API) OR local slice as fallback
  const searchResults = (() => {
    if (q.length >= 2) {
      const apiCards = apiResults.map(normalizeUserCard);
      const apiIds = new Set(apiCards.map(c=>c.id));
      const localOnly = localProfiles.filter(lp =>
        !apiIds.has(lp.id) &&
        (lp.username.includes(q) || lp.displayName.toLowerCase().includes(q) ||
         (lp.emailPrefix||'').includes(q))
      );
      return [...apiCards, ...localOnly];
    }
    if (q.length === 1) {
      return searchableUsers.filter(u =>
        u.username.startsWith(q) || u.displayName.toLowerCase().startsWith(q)
      ).slice(0,6);
    }
    // No query — show suggested fans if loaded, else local slice
    return suggestedFans.length > 0 ? suggestedFans.slice(0,6) : [];
  })();

  const circleMembers = circle;

  // ── Highlight matching query text ─────────────────────────────────────────
  const highlight = (text) => {
    if(!q || !text) return text;
    const idx = text.toLowerCase().indexOf(q);
    if(idx<0) return text;
    return <span>{text.slice(0,idx)}<span style={{ color:C.lavender,fontWeight:700 }}>{text.slice(idx,idx+q.length)}</span>{text.slice(idx+q.length)}</span>;
  };

  // ── Status button ─────────────────────────────────────────────────────────
  const StatusBtn = ({fu}) => {
    const st = getStatus(fu);
    if(st==="accepted") return <div style={{ display:"flex",alignItems:"center",gap:4,padding:"5px 12px",borderRadius:99,background:`${C.mint}18`,border:`1px solid ${C.mint}44`,fontSize:10,color:C.mint,fontFamily:"'Epilogue',sans-serif",fontWeight:700,whiteSpace:"nowrap" }}>In Your Circle ✦</div>;
    if(st==="sent")     return <div style={{ padding:"5px 12px",borderRadius:99,background:`${C.accent}12`,border:`1px solid ${C.accent}33`,fontSize:10,color:C.accent,fontFamily:"'Epilogue',sans-serif",fontWeight:700,whiteSpace:"nowrap" }}>Request Sent</div>;
    if(st==="declined") return <div style={{ padding:"5px 12px",borderRadius:99,background:`${C.textDim}22`,border:`1px solid ${C.border}`,fontSize:10,color:C.textDim,fontFamily:"'Epilogue',sans-serif",fontWeight:600,whiteSpace:"nowrap" }}>Declined</div>;
    return (
      <button onClick={()=>sendRequest(fu)} className="tap" style={{ padding:"6px 14px",borderRadius:99,background:`linear-gradient(135deg,${C.accent},${C.berry})`,border:"none",fontSize:10.5,color:C.bg,fontFamily:"'Epilogue',sans-serif",fontWeight:700,cursor:"pointer",whiteSpace:"nowrap",boxShadow:`0 0 12px ${C.accent}30` }}>Add to Circle</button>
    );
  };

  return (
    <div style={{ height:"100%",display:"flex",flexDirection:"column",overflow:"hidden" }}>

      {/* ── HEADER ── */}
      <div style={{ padding:"14px 20px 0",flexShrink:0,background:`linear-gradient(180deg,${C.cosmic},transparent)`,position:"relative",overflow:"hidden" }}>
        {/* Ambient orb */}
        <div style={{ position:"absolute",top:-30,right:-30,width:120,height:120,borderRadius:"50%",background:`radial-gradient(circle,${C.accent}12,transparent 70%)`,pointerEvents:"none" }} />
        <div style={{ display:"flex",gap:10,alignItems:"center",marginBottom:12,position:"relative",zIndex:1 }}>
          <button onClick={onBack} style={{ background:"none",border:"none",color:C.textMid,fontSize:22,cursor:"pointer" }}>←</button>
          <div style={{ flex:1,minWidth:0 }}>
            <div style={{ display:"flex",alignItems:"center",gap:7,marginBottom:2 }}>
              <h2 style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:900,fontSize:18,letterSpacing:"-0.02em",whiteSpace:"nowrap" }}>Bring Your Crew</h2>
              {/* Concert-safe chip — inline with title so title stays on one line */}
              <div style={{ padding:"3px 8px",borderRadius:99,background:`${C.mint}14`,border:`1px solid ${C.mint}30`,fontSize:8,color:C.mint,fontFamily:"'Epilogue',sans-serif",fontWeight:700,flexShrink:0 }}>✦ Safe</div>
            </div>
            <p style={{ fontSize:11,color:C.textMid }}>Find your people before the show.</p>
          </div>
        </div>
        <div style={{ display:"flex",gap:5,position:"relative",zIndex:1 }}>
          {[["find","Find Fans"],["invite","Invite"],["milestones","Rewards"]].map(([id,label])=>(
            <span key={id} onClick={()=>setTab(id)} className="tap" style={{ flex:1,textAlign:"center",padding:"7px 4px",borderRadius:11,fontSize:10.5,fontFamily:"'Epilogue',sans-serif",fontWeight:700,cursor:"pointer",background:tab===id?`linear-gradient(135deg,${C.accent},${C.berry})`:C.surfaceHi,color:tab===id?C.bg:C.textMid,border:`1px solid ${tab===id?"transparent":C.border}`,boxShadow:tab===id?`0 0 12px ${C.accent}28`:"none",transition:"all .18s",whiteSpace:"nowrap" }}>{label}</span>
          ))}
        </div>
        <div style={{ height:1,background:`linear-gradient(90deg,transparent,${C.borderHi},transparent)`,marginTop:12 }} />
      </div>

      <Screen style={{ padding:"0 0 calc(120px + env(safe-area-inset-bottom))" }}>

        {/* ══ FIND FANS TAB ══ */}
        {tab==="find" && (
          <div>
            {/* ── Constellation hero ── */}
            <div style={{ padding:"18px 20px 14px",background:`linear-gradient(160deg,${C.plum}40,${C.cosmic} 60%)`,position:"relative",overflow:"hidden",marginBottom:0 }}>
              {/* Constellation lines SVG */}
              <svg width="100%" height="56" style={{ position:"absolute",top:0,left:0,pointerEvents:"none",opacity:0.18 }} viewBox="0 0 350 56">
                <line x1="40" y1="28" x2="120" y2="18" stroke={C.lavender} strokeWidth="0.8"/>
                <line x1="120" y1="18" x2="200" y2="36" stroke={C.lavender} strokeWidth="0.8"/>
                <line x1="200" y1="36" x2="300" y2="14" stroke={C.lavender} strokeWidth="0.8"/>
                <circle cx="40" cy="28" r="2.5" fill={C.lavender}/><circle cx="120" cy="18" r="2.5" fill={C.pink}/><circle cx="200" cy="36" r="2.5" fill={C.lavender}/><circle cx="300" cy="14" r="2.5" fill={C.accent}/>
              </svg>
              {/* Floating avatar orbs */}
              {[
                {l:"6%",t:6,color:C.pink,init:"J"},{l:"28%",t:16,color:C.accent,init:"M"},
                {l:"52%",t:4,color:C.lavender,init:"K"},{l:"74%",t:18,color:C.mint,init:"Y"},{l:"88%",t:8,color:C.berry,init:"S"}
              ].map((o,i)=>(
                <div key={i} style={{ position:"absolute",left:o.l,top:o.t,width:28,height:28,borderRadius:"50%",background:`linear-gradient(135deg,${o.color},${o.color}88)`,border:`1.5px solid ${o.color}80`,display:"flex",alignItems:"center",justifyContent:"center",fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:10,color:C.bg,animation:`float ${3+i*0.4}s ease-in-out infinite`,animationDelay:`${i*0.55}s`,boxShadow:`0 0 10px ${o.color}44` }}>{o.init}</div>
              ))}
              <div style={{ height:50 }} />
            </div>

            {/* ── Search input ── */}
            <div style={{ padding:"14px 20px 0",position:"relative",zIndex:10 }}>
              <div style={{ position:"relative",marginBottom:searchResults.length>0&&(q||searchFocused)?0:14 }}>
                <div style={{ position:"absolute",left:14,top:"50%",transform:"translateY(-50%)",fontSize:15,color:C.accent,pointerEvents:"none",zIndex:2 }}>✦</div>
                <input
                  value={searchQ}
                  onChange={e=>setSearchQ(e.target.value)}
                  onFocus={()=>setSearchFocused(true)}
                  onBlur={()=>setTimeout(()=>setSearchFocused(false),160)}
                  placeholder="Search a username, moot, or concert friend…"
                  style={{ width:"100%",padding:"13px 14px 13px 38px",borderRadius:18,background:`linear-gradient(135deg,${C.surfaceMid},${C.surface})`,border:`1.5px solid ${searchFocused?C.accent:C.borderHi}`,color:C.text,fontSize:13,fontFamily:"'Instrument Sans',sans-serif",outline:"none",boxSizing:"border-box",boxShadow:searchFocused?`0 0 18px ${C.accent}22`:"none",transition:"all .2s" }}
                />
                {searchQ&&<button onClick={()=>setSearchQ("")} style={{ position:"absolute",right:12,top:"50%",transform:"translateY(-50%)",background:"none",border:"none",color:C.textMid,fontSize:16,cursor:"pointer",padding:4 }}>✕</button>}
              </div>

              {/* ── Search results / suggestions ── */}
              {(searchResults.length > 0 || q.length >= 1 || searching) && (
                <div style={{ background:`linear-gradient(160deg,${C.surfaceMid},${C.surface})`,border:`1.5px solid ${C.borderHi}`,borderRadius:18,overflow:"hidden",marginBottom:16,animation:"searchSlideIn .18s ease",boxShadow:`0 8px 28px rgba(0,0,0,0.4)` }}>

                  {/* Section label — only when showing suggestions (no query) */}
                  {!q && searchResults.length > 0 && (
                    <div style={{ padding:"10px 14px 6px",borderBottom:`1px solid ${C.border}` }}>
                      <p style={{ fontSize:9.5,fontFamily:"'Epilogue',sans-serif",fontWeight:700,color:C.textDim,textTransform:"uppercase",letterSpacing:"0.09em" }}>✦ Suggested for you</p>
                    </div>
                  )}

                  {/* Loading indicator */}
                  {searching && (
                    <div style={{ padding:"16px 14px",display:"flex",alignItems:"center",gap:10 }}>
                      <div style={{ width:16,height:16,borderRadius:"50%",border:`2px solid ${C.accent}`,borderTopColor:"transparent",animation:"rotate .7s linear infinite",flexShrink:0 }} />
                      <p style={{ fontSize:11.5,color:C.textMid }}>Searching Backstage…</p>
                    </div>
                  )}

                  {/* Result rows */}
                  {!searching && searchResults.map((fu,i)=>{
                    const st = getStatus(fu);
                    return (
                      <div key={fu.id} style={{ padding:"11px 14px",borderBottom:i<searchResults.length-1?`1px solid ${C.border}`:"none",position:"relative",background:st==="accepted"?`${C.mint}05`:"transparent" }}>
                        <div style={{ display:"flex",gap:10,alignItems:"flex-start" }}>
                          <div style={{ position:"relative",flexShrink:0,marginTop:2 }}>
                            <div style={{ width:42,height:42,borderRadius:"50%",background:`linear-gradient(135deg,${fu.color||C.accent},${(fu.color||C.accent)}77)`,display:"flex",alignItems:"center",justifyContent:"center",fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:15,color:C.bg,border:`2px solid ${(fu.color||C.accent)}66`,boxShadow:`0 0 12px ${(fu.color||C.accent)}33` }}>{fu.avatar}</div>
                            {st==="accepted"&&<div style={{ position:"absolute",bottom:-1,right:-1,width:14,height:14,borderRadius:"50%",background:C.mint,border:`2px solid ${C.surface}`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:7 }}>✦</div>}
                          </div>
                          <div style={{ flex:1,minWidth:0,overflow:"hidden" }}>
                            <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:12.5,color:C.text,marginBottom:2,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap" }}>{highlight(`@${fu.username}`)}</p>
                            <p style={{ fontSize:10,color:C.textMid,marginBottom:5,lineHeight:1.35,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap" }}>{fu.bio||fu.displayName}</p>
                            <div style={{ display:"flex",gap:4,flexWrap:"nowrap",overflow:"hidden" }}>
                              {(fu.fandoms||[]).slice(0,1).map(f=><span key={f} style={{ padding:"2px 8px",borderRadius:99,background:`${(fu.color||C.accent)}18`,border:`1px solid ${(fu.color||C.accent)}33`,fontSize:9,color:fu.color||C.accent,fontFamily:"'Epilogue',sans-serif",fontWeight:700,whiteSpace:"nowrap",flexShrink:0 }}>{f}</span>)}
                              {fu.city&&<span style={{ padding:"2px 8px",borderRadius:99,background:C.surfaceHi,border:`1px solid ${C.border}`,fontSize:9,color:C.textMid,fontFamily:"'Epilogue',sans-serif",fontWeight:600,whiteSpace:"nowrap",flexShrink:0 }}>📍 {fu.city.split(",")[0]}</span>}
                              {fu.concertContext&&<span style={{ fontSize:9,color:C.textDim,fontStyle:"italic",whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis",flexShrink:1 }}>🎤 {fu.concertContext.split(" ").slice(0,3).join(" ")}</span>}
                            </div>
                          </div>
                          <div style={{ flexShrink:0,marginTop:2 }}><StatusBtn fu={fu} /></div>
                        </div>
                      </div>
                    );
                  })}

                  {/* No-results fallback — never a dead end */}
                  {!searching && q.length >= 2 && searchResults.length === 0 && (
                    <div style={{ padding:"22px 18px" }}>
                      <div style={{ textAlign:"center",marginBottom:16 }}>
                        <div style={{ fontSize:28,marginBottom:8 }}>🔭</div>
                        <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:13,marginBottom:5 }}>No profile found for @{q}</p>
                        <p style={{ fontSize:11.5,color:C.textMid,lineHeight:1.6 }}>They might not be on Backstage yet.<br/>Send them your invite link or show your QR.</p>
                      </div>
                      <div style={{ display:"flex",gap:7,flexWrap:"wrap",justifyContent:"center" }}>
                        <button onMouseDown={e=>e.preventDefault()} onClick={simulateInvite} className="tap"
                          style={{ padding:"8px 14px",borderRadius:99,background:C.accent,border:"none",color:C.bg,fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:11,cursor:"pointer" }}>
                          📨 Send Invite
                        </button>
                        <button onMouseDown={e=>e.preventDefault()} onClick={copyLink} className="tap"
                          style={{ padding:"8px 14px",borderRadius:99,background:`${C.accent}18`,border:`1px solid ${C.accent}44`,color:C.accent,fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:11,cursor:"pointer" }}>
                          {copied?"✓ Copied":"🔗 Copy Link"}
                        </button>
                        {go && (
                          <button onMouseDown={e=>e.preventDefault()} onClick={()=>go('qr')} className="tap"
                            style={{ padding:"8px 14px",borderRadius:99,background:`${C.lavender}18`,border:`1px solid ${C.lavender}44`,color:C.lavender,fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:11,cursor:"pointer" }}>
                            ◈ My QR
                          </button>
                        )}
                        <button onMouseDown={e=>e.preventDefault()} onClick={()=>setSearchQ("")} className="tap"
                          style={{ padding:"8px 14px",borderRadius:99,background:C.surfaceHi,border:`1px solid ${C.border}`,color:C.textMid,fontFamily:"'Epilogue',sans-serif",fontWeight:600,fontSize:11,cursor:"pointer" }}>
                          ✕ Clear
                        </button>
                      </div>
                    </div>
                  )}
                </div>
              )}
            </div>

            {/* ── My Circle ── */}
            <div style={{ padding:"0 20px" }}>
              <div style={{ marginBottom:12 }}>
                <div style={{ display:"flex",alignItems:"center",gap:8,marginBottom:3 }}>
                  <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:13.5,flex:1 }}>Your Circle</p>
                  {circleMembers.length>0&&<div style={{ padding:"3px 10px",borderRadius:99,background:`${C.accent}14`,border:`1px solid ${C.accent}28`,fontSize:9,color:C.accent,fontFamily:"'Epilogue',sans-serif",fontWeight:700 }}>{circleMembers.length} {circleMembers.length===1?"person":"people"}</div>}
                </div>
                <p style={{ fontSize:10.5,color:C.textMid,lineHeight:1.5 }}>Your concert people — fans you stay connected with before and after the show.</p>
              </div>

              {circleMembers.length===0 ? (
                <div style={{ background:`linear-gradient(140deg,${C.surfaceMid},${C.surface})`,border:`1.5px solid ${C.border}`,borderRadius:20,padding:"24px 20px",textAlign:"center",position:"relative",overflow:"hidden" }}>
                  <div style={{ position:"absolute",inset:0,background:`radial-gradient(ellipse at 50% 0%,${C.accent}05,transparent 70%)`,pointerEvents:"none" }} />
                  <div style={{ fontSize:34,marginBottom:10,animation:"float 3s ease-in-out infinite" }}>🌌</div>
                  <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:14,marginBottom:6 }}>Your Circle is waiting</p>
                  <p style={{ fontSize:12,color:C.textMid,lineHeight:1.6,marginBottom:14 }}>Add your first concert friend above.<br/>Find your people before the show.</p>
                  <div style={{ display:"flex",gap:6,justifyContent:"center",flexWrap:"wrap" }}>
                    {["@armyjoon","@staymia","@purplehour"].map(u=>(
                      <button key={u} onClick={()=>setSearchQ(u.slice(1))} className="tap" style={{ padding:"5px 12px",borderRadius:99,background:C.surfaceHi,border:`1px solid ${C.border}`,fontSize:10.5,color:C.textMid,cursor:"pointer",fontFamily:"'Instrument Sans',sans-serif" }}>{u}</button>
                    ))}
                  </div>
                </div>
              ) : (
                <div style={{ background:`linear-gradient(140deg,${C.surfaceMid},${C.surface})`,border:`1.5px solid ${C.borderHi}`,borderRadius:20,padding:16,position:"relative",overflow:"hidden" }}>
                  <div style={{ position:"absolute",top:0,left:0,right:0,height:1,background:`linear-gradient(90deg,transparent,${C.lavender}33,transparent)` }} />
                  {/* Sparkle dots */}
                  {[{t:"8%",l:"85%"},{t:"75%",l:"6%"},{t:"45%",l:"92%"}].map((s,i)=>(
                    <div key={i} style={{ position:"absolute",top:s.t,left:s.l,fontSize:9,color:C.pink,opacity:0.3,animation:`sparkleFloat ${3+i*0.7}s ease-in-out infinite`,pointerEvents:"none" }}>✦</div>
                  ))}
                  <div style={{ display:"flex",gap:12,overflowX:"auto",paddingBottom:4,scrollbarWidth:"none" }}>
                    {circleMembers.slice(0,8).map((m,i)=>(
                      <div key={m.id||i} style={{ flexShrink:0,display:"flex",flexDirection:"column",alignItems:"center",gap:5 }}>
                        <div style={{ position:"relative" }}>
                          <div style={{ width:52,height:52,borderRadius:"50%",background:`linear-gradient(135deg,${m.color},${m.color}66)`,display:"flex",alignItems:"center",justifyContent:"center",fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:19,color:C.bg,border:`2.5px solid ${m.color}`,boxShadow:`0 0 16px ${m.color}44` }}>{m.avatar}</div>
                          <div style={{ position:"absolute",top:2,right:2,width:12,height:12,borderRadius:"50%",background:C.mint,border:`2px solid ${C.surfaceMid}`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:6.5 }}>✦</div>
                        </div>
                        <p style={{ fontSize:9,fontFamily:"'Epilogue',sans-serif",fontWeight:700,color:m.color,maxWidth:52,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",textAlign:"center" }}>{m.name?.replace("@","")}</p>
                        {m.groups?.[0]&&<span style={{ fontSize:7.5,padding:"1.5px 6px",borderRadius:99,background:`${m.color}18`,border:`1px solid ${m.color}28`,color:m.color,fontFamily:"'Epilogue',sans-serif",fontWeight:700 }}>{m.groups[0]}</span>}
                      </div>
                    ))}
                    {circleMembers.length>8&&(
                      <div style={{ flexShrink:0,display:"flex",flexDirection:"column",alignItems:"center",gap:5 }}>
                        <div style={{ width:52,height:52,borderRadius:"50%",background:C.surfaceHi,border:`2px dashed ${C.border}`,display:"flex",alignItems:"center",justifyContent:"center" }}>
                          <p style={{ fontSize:11,fontFamily:"'Epilogue',sans-serif",fontWeight:700,color:C.textMid }}>+{circleMembers.length-8}</p>
                        </div>
                        <p style={{ fontSize:9,color:C.textDim }}>more</p>
                      </div>
                    )}
                  </div>
                </div>
              )}

              {/* Pending requests */}
              {pendingReqs.length>0&&(
                <div style={{ marginTop:14 }}>
                  <p style={{ fontSize:10,color:C.textMid,fontFamily:"'Epilogue',sans-serif",fontWeight:600,textTransform:"uppercase",letterSpacing:"0.1em",marginBottom:8 }}>Pending — {pendingReqs.length} sent</p>
                  {pendingReqs.map(req=>(
                    <div key={req.id} style={{ display:"flex",gap:10,alignItems:"center",background:C.surface,border:`1px solid ${C.accent}22`,borderRadius:14,padding:"10px 12px",marginBottom:8 }}>
                      <div style={{ width:36,height:36,borderRadius:"50%",background:`linear-gradient(135deg,${req.color},${req.color}77)`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:13,fontFamily:"'Epilogue',sans-serif",fontWeight:800,color:C.bg,flexShrink:0 }}>{req.avatar}</div>
                      <div style={{ flex:1,minWidth:0 }}>
                        <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:12 }}>@{req.username}</p>
                        <p style={{ fontSize:10,color:C.textMid }}>{req.concertContext||req.fandoms?.[0]||""}</p>
                      </div>
                      <div style={{ padding:"4px 10px",borderRadius:99,background:`${C.accent}12`,border:`1px solid ${C.accent}28`,fontSize:9.5,color:C.accent,fontFamily:"'Epilogue',sans-serif",fontWeight:700,flexShrink:0 }}>Request Sent</div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        )}

        {/* ══ INVITE TAB ══ */}
        {tab==="invite" && (
          <div style={{ padding:"16px 20px 0" }}>
            {/* Hero card */}
            <div style={{ background:`linear-gradient(140deg,${C.accent}18,${C.pink}12)`,border:`1.5px solid ${C.accent}40`,borderRadius:22,padding:20,marginBottom:18,textAlign:"center",position:"relative",overflow:"hidden",animation:"shareGlow 4s ease infinite" }}>
              <div style={{ position:"absolute",inset:0,background:`radial-gradient(ellipse at top,${C.accent}0a,transparent 70%)`,pointerEvents:"none" }} />
              <div style={{ fontSize:40,marginBottom:10,animation:"float 3s ease infinite",display:"inline-block" }}>🎤</div>
              <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:900,fontSize:20,marginBottom:4 }}>Your Invite Code</p>
              <div style={{ background:C.surfaceHi,borderRadius:13,padding:"12px 16px",marginBottom:14,border:`1.5px solid ${C.accent}44` }}>
                <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:900,fontSize:16,color:C.accent,letterSpacing:"0.1em" }}>{myCode}</p>
              </div>
              <div style={{ display:"flex",gap:8 }}>
                <button onClick={copyLink} className="tap" style={{ flex:1,padding:"11px",borderRadius:12,background:copied?`${C.mint}22`:"transparent",border:`1.5px solid ${copied?C.mint:C.accent}55`,color:copied?C.mint:C.accent,fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:12,cursor:"pointer",transition:"all .2s" }}>{copied?"✓ Copied!":"📋 Copy Link"}</button>
                <button onClick={simulateInvite} className="tap" style={{ flex:1,padding:"11px",borderRadius:12,background:C.accent,border:"none",color:C.bg,fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:12,cursor:"pointer" }}>📨 Share Invite</button>
              </div>
              {referralSetupRequired && (
                <p style={{ fontSize:10.5,color:C.gold,marginTop:10,lineHeight:1.5 }}>
                  Referral database setup is pending. This link is safe to share, but rewards start counting after the Supabase referral tables are installed.
                </p>
              )}
            </div>

            {/* QR Card */}
            <div style={{ background:C.surface,border:`1.5px solid ${C.border}`,borderRadius:18,padding:18,marginBottom:14,textAlign:"center" }}>
              <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:13,marginBottom:12,color:C.textMid }}>📱 QR Code Invite</p>
              <div style={{ width:120,height:120,margin:"0 auto 12px",background:C.surfaceHi,borderRadius:14,border:`2px solid ${C.accent}33`,display:"flex",alignItems:"center",justifyContent:"center",overflow:"hidden" }}>
                <img src={`https://api.qrserver.com/v1/create-qr-code/?size=180x180&margin=10&data=${encodeURIComponent(myLink)}`} alt="Invite QR code" style={{ width:"100%",height:"100%",display:"block" }} />
              </div>
              <p style={{ fontSize:11,color:C.textMid }}>Scan to join Backstage as your crew</p>
            </div>

            {/* What they get */}
            <div style={{ background:C.surface,border:`1px solid ${C.border}`,borderRadius:18,padding:16 }}>
              <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:13,marginBottom:12,color:C.silver }}>Both of you get 🎁</p>
              {[
                ["✨","VIP 7-day Trial","Access all premium features"],
                [null,"Founding Fan Badge","Your permanent first-era collectible"],
                ["💜","Crew Tag","Your connection on each other's profiles"]
              ].map(([emoji,label,sub],i)=>(
                <div key={i} style={{ display:"flex",gap:10,alignItems:"center",padding:"8px 0",borderBottom:i<2?`1px solid ${C.border}`:"none" }}>
                  <div style={{ width:38,height:38,borderRadius:11,background:`${C.accent}18`,border:`1px solid ${C.accent}33`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:16,flexShrink:0 }}>{emoji||"✦"}</div>
                  <div>
                    {i===1 ? <div style={{ marginBottom:2 }}><FounderBadge inline /></div> : <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:600,fontSize:12.5 }}>{label}</p>}
                    <p style={{ fontSize:10.5,color:C.textMid }}>{sub}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* ══ REWARDS TAB ══ */}
        {tab==="milestones" && (
          <div style={{ padding:"16px 20px 0" }}>
            <div style={{ background:`${C.gold}0a`,border:`1px solid ${C.gold}22`,borderRadius:14,padding:"11px 14px",marginBottom:18 }}>
              <p style={{ fontSize:12,color:C.textMid }}>💜 You've converted <span style={{ color:C.gold,fontWeight:700 }}>{converted} friend{converted!==1?"s":""}</span>. Next milestone: <span style={{ color:C.mint,fontWeight:700 }}>{nextMilestone.reward}</span></p>
            </div>
            <div style={{ marginBottom:14 }}>
              <ProgressBar value={(converted/10)*100} color={C.gold} />
              <div style={{ display:"flex",justifyContent:"space-between",marginTop:5 }}>
                <p style={{ fontSize:10,color:C.textMid }}>{converted}/10 friends</p>
                <p style={{ fontSize:10,color:C.gold }}>Pioneer Badge →</p>
              </div>
            </div>
            {REFERRAL_MILESTONES.map((m,i)=>{
              const unlocked = converted>=m.count;
              const isFounderMilestone = m.reward==="Founder Badge";
              return (
                <div key={i} style={{ background:unlocked?`${m.color}12`:C.surface,border:`1.5px solid ${unlocked?m.color:C.border}`,borderRadius:18,padding:16,marginBottom:10,display:"flex",gap:14,alignItems:"center",transition:"all .22s" }}>
                  <div style={{ width:48,height:48,borderRadius:14,background:`${m.color}22`,border:`1.5px solid ${m.color}${unlocked?"88":"33"}`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:22,flexShrink:0 }}>{m.icon}</div>
                  <div style={{ flex:1 }}>
                    <div style={{ display:"flex",gap:8,alignItems:"center",marginBottom:3 }}>
                      {isFounderMilestone
                        ? <FounderBadge inline />
                        : <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:13.5,color:unlocked?m.color:C.text }}>{m.reward}</p>
                      }
                      {unlocked&&<Pill color={C.mint} active xs>Unlocked</Pill>}
                    </div>
                    <p style={{ fontSize:11,color:C.textMid }}>{m.desc} · {m.count} friend{m.count!==1?"s":""}</p>
                  </div>
                  {unlocked?<span style={{ fontSize:20 }}>✓</span>:<span style={{ fontSize:12,color:C.textDim }}>{m.count-converted} left</span>}
                </div>
              );
            })}
          </div>
        )}
      </Screen>

      {/* Reward toast */}
      {showReward && (
        <div style={{ position:"absolute",top:80,left:16,right:16,zIndex:900,animation:"viralPop .3s ease" }}>
          <div style={{ background:`${C.accent}f0`,borderRadius:18,padding:"14px 18px",backdropFilter:"blur(20px)",textAlign:"center" }}>
            <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:900,fontSize:15,color:C.bg }}>Invite link copied. Rewards unlock after confirmed signup.</p>
          </div>
        </div>
      )}
    </div>
  );
}

// ─── CONTENT GENERATOR ────────────────────────────────────────────────────────
// POST /api/content/generate-card | POST /api/content/generate-snapshot
function ContentGenerator({ onBack, user, go, onNotif }) {
  const [mode, setMode] = useState("menu");
  const [generating, setGenerating] = useState(false);
  const [done, setDone] = useState(false);

  const generate = (type) => {
    setGenerating(true); setDone(false);
    setTimeout(()=>{ setGenerating(false); setDone(true); onNotif({title:`${type} ready! ✨`,body:"Tap Share to post it.",icon:"✨",color:C.accent}); },2200);
  };

  if(mode==="concertday") return <ConcertDayCard onBack={()=>{setMode("menu");setDone(false);}} user={user} generate={generate} generating={generating} done={done} onNotif={onNotif} go={go} />;
  if(mode==="identity") return <IdentityCard onBack={()=>{setMode("menu");setDone(false);}} user={user} />;
  if(mode==="mapsnapshot") return <MapSnapshot onBack={()=>{setMode("menu");setDone(false);}} />;

  return (
    <div style={{ height:"100%",display:"flex",flexDirection:"column",overflow:"hidden" }}>
      <div style={{ padding:"16px 20px",display:"flex",gap:10,alignItems:"center",flexShrink:0 }}>
        <button onClick={onBack} style={{ background:"none",border:"none",color:C.textMid,fontSize:22,cursor:"pointer" }}>←</button>
        <div>
          <h2 style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:900,fontSize:20 }}>Content Studio ✨</h2>
          <p style={{ fontSize:11,color:C.textMid }}>Make shareable fan content</p>
        </div>
      </div>
      <Screen style={{ padding:"0 20px calc(120px + env(safe-area-inset-bottom))" }}>
        <div style={{ paddingTop:8 }}>
          {[
            { id:"concertday", emoji:"🎤", title:"My Concert Day", sub:"Auto-generate your concert timeline as a beautiful story card", color:C.pink, badge:"Trending" },
            { id:"identity", emoji:"🌟", title:"Fan Identity Card", sub:"Your fan stats, groups, and era. Shareable flex card.", color:C.accent, badge:"Fan Fav" },
            { id:"mapsnapshot", emoji:"🗺️", title:"Fan Map Snapshot", sub:"Your presence on the Fanverse map. Show where you stan.", color:C.mint, badge:"New" },
          ].map(card=>(
            <div key={card.id} onClick={()=>setMode(card.id)} className="tap" style={{ background:`linear-gradient(140deg,${card.color}14,${card.color}06)`,border:`1.5px solid ${card.color}40`,borderRadius:22,padding:20,marginBottom:14,cursor:"pointer",position:"relative",overflow:"hidden" }}>
              <div style={{ position:"absolute",inset:0,background:`radial-gradient(ellipse at top right,${card.color}08,transparent 70%)`,pointerEvents:"none" }} />
              <div style={{ display:"flex",gap:14,alignItems:"center",marginBottom:12 }}>
                <div style={{ width:54,height:54,borderRadius:16,background:`${card.color}22`,border:`1.5px solid ${card.color}55`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:26,flexShrink:0 }}>{card.emoji}</div>
                <div style={{ flex:1 }}>
                  <div style={{ display:"flex",gap:6,alignItems:"center",marginBottom:3 }}>
                    <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:16 }}>{card.title}</p>
                    <Pill color={card.color} active xs>{card.badge}</Pill>
                  </div>
                  <p style={{ fontSize:12,color:C.textMid,lineHeight:1.5 }}>{card.sub}</p>
                </div>
              </div>
              <div style={{ display:"flex",justifyContent:"flex-end" }}>
                <span style={{ fontSize:11,color:card.color,fontFamily:"'Epilogue',sans-serif",fontWeight:700 }}>Create →</span>
              </div>
            </div>
          ))}

          <div style={{ background:C.surfaceHi,border:`1px solid ${C.border}`,borderRadius:16,padding:14,marginTop:4 }}>
            <p style={{ fontSize:11.5,color:C.textMid,textAlign:"center" }}>📸 More generators coming — Haul Card, Trade Portfolio, Concert Recap Video</p>
          </div>
        </div>
      </Screen>
    </div>
  );
}

function ConcertDayCard({ onBack, user, generate, generating, done, onNotif, go }) {
  const [concert, setConcert] = useState(MOCK_CONCERTS[0]);
  const [moments, setMoments] = useState(CONCERT_DAY_MOMENTS.map(m=>({...m,include:true})));
  const [mood, setMood] = useState("floating");
  const [shared, setShared] = useState(false);

  const shareCard = () => {
    navigator.clipboard?.writeText(`My concert day at ${concert.name}! 💜 #Backstage #${concert.group.replace(" ","")}`).catch(()=>{});
    setShared(true);
    onNotif({title:"Shared! 💜",body:"Your concert day card is ready to post.",icon:"💜",color:C.pink});
  };

  return (
    <div style={{ height:"100%",display:"flex",flexDirection:"column",overflow:"hidden" }}>
      <div style={{ padding:"16px 20px",display:"flex",gap:10,alignItems:"center",flexShrink:0 }}>
        <button onClick={onBack} style={{ background:"none",border:"none",color:C.textMid,fontSize:22,cursor:"pointer" }}>←</button>
        <h2 style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:19 }}>My Concert Day 🎤</h2>
      </div>
      <Screen style={{ padding:"0 20px calc(120px + env(safe-area-inset-bottom))" }}>
        {/* Preview card */}
        <div style={{ background:`linear-gradient(160deg,${concert.color}28,${C.accent}10,${C.pink}08)`,border:`1.5px solid ${concert.color}50`,borderRadius:24,padding:20,marginBottom:18,animation:"shareGlow 4s ease infinite" }}>
          <div style={{ display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16 }}>
            <div><p style={{ fontSize:9,color:concert.color,fontFamily:"'Epilogue',sans-serif",fontWeight:700,textTransform:"uppercase",letterSpacing:"0.14em" }}>BACKSTAGE · MY CONCERT DAY</p><p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:900,fontSize:18,marginTop:3 }}>{concert.name}</p><p style={{ fontSize:11.5,color:C.textMid }}>{concert.city} · {concert.date}</p></div>
            <div style={{ fontSize:30 }}>🎤</div>
          </div>
          <div style={{ display:"flex",flexDirection:"column",gap:6 }}>
            {moments.filter(m=>m.include).map((m,i)=>(
              <div key={i} style={{ display:"flex",gap:10,alignItems:"center",padding:"7px 10px",background:"rgba(255,255,255,0.04)",borderRadius:10,border:`1px solid ${concert.color}18` }}>
                <span style={{ fontSize:14,flexShrink:0 }}>{m.emoji}</span>
                <p style={{ fontSize:10,fontFamily:"'Epilogue',sans-serif",fontWeight:700,color:concert.color,width:50,flexShrink:0 }}>{m.time}</p>
                <p style={{ fontSize:11.5,fontWeight:600 }}>{m.title}</p>
              </div>
            ))}
          </div>
          <div style={{ marginTop:14,display:"flex",justifyContent:"space-between",alignItems:"center" }}>
            <p style={{ fontSize:10,color:C.textDim,fontStyle:"italic" }}>@{user?.username||user?.username||user?.name||user?.stanName||"stan"} · Backstage App</p>
            <p style={{ fontSize:18 }}>{MOCK_AFTERGLOW_MOODS.find(m=>m.id===mood)?.emoji||"✨"}</p>
          </div>
        </div>

        {/* Mood */}
        <SectionHeader title="Concert Mood" />
        <div style={{ display:"flex",gap:7,overflowX:"auto",paddingBottom:8,marginBottom:16 }}>
          {MOCK_AFTERGLOW_MOODS.map(m=>(
            <span key={m.id} onClick={()=>setMood(m.id)} className="tap" style={{ flexShrink:0,padding:"6px 12px",borderRadius:99,fontSize:11,fontFamily:"'Epilogue',sans-serif",fontWeight:600,cursor:"pointer",background:mood===m.id?C.accent:C.surfaceHi,color:mood===m.id?C.bg:C.textMid,border:`1px solid ${mood===m.id?C.accent:C.border}` }}>{m.label}</span>
          ))}
        </div>

        {/* Moments toggle */}
        <SectionHeader title="Timeline Moments" />
        {moments.map((m,i)=>(
          <div key={i} onClick={()=>{const next=[...moments];next[i]={...m,include:!m.include};setMoments(next);}} className="tap" style={{ display:"flex",gap:10,alignItems:"center",background:m.include?`${C.accent}0a`:C.surface,border:`1.5px solid ${m.include?C.accent:C.border}`,borderRadius:13,padding:"10px 13px",marginBottom:8,cursor:"pointer",transition:"all .2s" }}>
            <span style={{ fontSize:16 }}>{m.emoji}</span>
            <div style={{ flex:1 }}><p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:600,fontSize:12.5 }}>{m.title}</p><p style={{ fontSize:10.5,color:C.textMid }}>{m.time}</p></div>
            <div style={{ width:20,height:20,borderRadius:"50%",border:`1.5px solid ${m.include?C.accent:C.border}`,background:m.include?C.accent:"transparent",display:"flex",alignItems:"center",justifyContent:"center",fontSize:11,color:C.bg }}>{m.include?"✓":""}</div>
          </div>
        ))}

        <div style={{ display:"flex",gap:10,marginTop:8 }}>
          {done ? (
            <button onClick={shareCard} className="tap" style={{ flex:1,padding:"14px",borderRadius:14,background:shared?`${C.mint}22`:`linear-gradient(140deg,${C.pink},${C.accent})`,border:"none",color:shared?C.mint:C.bg,fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:13.5,cursor:"pointer",boxShadow:`0 4px 22px ${C.pink}30`,animation:shared?"none":"shareGlow 3s ease infinite" }}>{shared?"✓ Shared to Feed!":"💜 Share My Concert Day"}</button>
          ) : (
            <button onClick={()=>generate("Concert Day Card")} disabled={generating} className="tap" style={{ flex:1,padding:"14px",borderRadius:14,background:generating?`${C.accent}44`:`linear-gradient(140deg,${C.accent},${C.pink})`,border:"none",color:C.bg,fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:13.5,cursor:generating?"wait":"pointer",boxShadow:`0 4px 22px ${C.accent}30` }}>{generating?"Generating...":"✨ Generate Card"}</button>
          )}
        </div>

        {/* Concert Capsule entry */}
        <div onClick={()=>go?.("capsule")} style={{ marginTop:14,background:`linear-gradient(140deg,${C.plum},${C.cosmic})`,border:`1.5px solid ${C.accent}44`,borderRadius:20,padding:"16px 18px",cursor:"pointer",position:"relative",overflow:"hidden" }}>
          <div style={{ position:"absolute",top:0,left:0,right:0,height:1,background:`linear-gradient(90deg,transparent,${C.accent}66,transparent)` }} />
          {[{t:"12%",l:"78%",s:11,d:"0s"},{t:"65%",l:"86%",s:8,d:"0.8s"}].map((sp,i)=>(
            <div key={i} style={{ position:"absolute",top:sp.t,left:sp.l,fontSize:sp.s,opacity:0.5,animation:`sparkleFloat 3.5s ease-in-out infinite`,animationDelay:sp.d,pointerEvents:"none",color:C.lavender }}>✦</div>
          ))}
          <div style={{ position:"relative",display:"flex",gap:12,alignItems:"center" }}>
            <div style={{ fontSize:28 }}>📸</div>
            <div style={{ flex:1 }}>
              <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:14,color:C.lavender,marginBottom:3 }}>Concert Capsule ✦</p>
              <p style={{ fontSize:11,color:C.textMid,lineHeight:1.5 }}>See what every fan captured tonight. Add your memory to the shared archive.</p>
            </div>
            <span style={{ color:C.accent,fontSize:18 }}>→</span>
          </div>
        </div>
      </Screen>
    </div>
  );
}

function IdentityCard({ onBack, user }) {
  const [shared, setShared] = useState(false);
  const STATS = [
    { label:"Shows Attended", value:"2", icon:"🎤" },
    { label:"Cards Collected", value:"6+", icon:"🃏" },
    { label:"Fandoms", value:"5", icon:"💜" },
    { label:"Trades Done", value:"3", icon:"⇄" },
    { label:"Cities Traveled", value:"2", icon:"✈️" },
    { label:"Memories", value:"12", icon:"📸" },
  ];
  const TYPE = "Tour Chaser";
  const TOP_GROUPS = ["Stray Kids","BTS","aespa"];

  return (
    <div style={{ height:"100%",display:"flex",flexDirection:"column",overflow:"hidden" }}>
      <div style={{ padding:"16px 20px",display:"flex",gap:10,alignItems:"center",flexShrink:0 }}>
        <button onClick={onBack} style={{ background:"none",border:"none",color:C.textMid,fontSize:22,cursor:"pointer" }}>←</button>
        <h2 style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:19 }}>Fan Identity Card 🌟</h2>
      </div>
      <Screen style={{ padding:"0 20px calc(120px + env(safe-area-inset-bottom))" }}>
        {/* Card */}
        <div style={{ background:`linear-gradient(160deg,${C.accentDim},${C.accent}88,${C.pinkDim})`,borderRadius:24,padding:22,marginBottom:18,position:"relative",overflow:"hidden",animation:"shareGlow 4s ease infinite" }}>
          {/* glow orb */}
          <div style={{ position:"absolute",top:-30,right:-30,width:120,height:120,borderRadius:"50%",background:`${C.pink}30`,filter:"blur(30px)",pointerEvents:"none" }} />
          <div style={{ display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:18,zIndex:1,position:"relative" }}>
            <div>
              <p style={{ fontSize:9,color:"rgba(255,255,255,0.65)",fontFamily:"'Epilogue',sans-serif",fontWeight:700,textTransform:"uppercase",letterSpacing:"0.16em",marginBottom:4 }}>BACKSTAGE · FAN IDENTITY</p>
              <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:900,fontSize:24,color:C.white,lineHeight:1 }}>@{user?.username||user?.username||user?.name||user?.stanName||"stan"}</p>
            </div>
            <div style={{ width:50,height:50,borderRadius:14,background:"rgba(255,255,255,0.15)",border:"1.5px solid rgba(255,255,255,0.25)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:24,backdropFilter:"blur(8px)" }}>🎤</div>
          </div>
          {/* Fan type */}
          <div style={{ background:"rgba(255,255,255,0.14)",borderRadius:12,padding:"8px 14px",marginBottom:16,backdropFilter:"blur(8px)",display:"inline-flex",gap:8,alignItems:"center" }}>
            <span style={{ fontSize:16 }}>🌟</span>
            <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:14,color:C.white }}>Fan Type: {TYPE}</p>
          </div>
          {/* Groups */}
          <div style={{ display:"flex",gap:6,flexWrap:"wrap",marginBottom:18 }}>
            {TOP_GROUPS.map(g=><span key={g} style={{ padding:"4px 12px",borderRadius:99,background:"rgba(255,255,255,0.18)",color:C.white,fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:11,backdropFilter:"blur(8px)" }}>{g}</span>)}
          </div>
          {/* Stats grid */}
          <div style={{ display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8 }}>
            {STATS.map((s,i)=>(
              <div key={i} style={{ background:"rgba(255,255,255,0.12)",borderRadius:12,padding:"9px 10px",backdropFilter:"blur(8px)",textAlign:"center" }}>
                <p style={{ fontSize:18,marginBottom:2 }}>{s.icon}</p>
                <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:900,fontSize:18,color:C.white,lineHeight:1 }}>{s.value}</p>
                <p style={{ fontSize:8.5,color:"rgba(255,255,255,0.7)",lineHeight:1.3,marginTop:3,fontFamily:"'Epilogue',sans-serif",fontWeight:600,textTransform:"uppercase",letterSpacing:"0.05em" }}>{s.label}</p>
              </div>
            ))}
          </div>
          {/* Footer */}
          <div style={{ marginTop:14,display:"flex",justifyContent:"space-between",alignItems:"center" }}>
            <p style={{ fontSize:9,color:"rgba(255,255,255,0.5)",fontFamily:"'Epilogue',sans-serif",fontWeight:600 }}>2026 · FANVERSE</p>
            <p style={{ fontSize:9,color:"rgba(255,255,255,0.5)",fontFamily:"'Epilogue',sans-serif",fontWeight:600 }}>backstagefanverse.com</p>
          </div>
        </div>

        <button onClick={()=>{navigator.clipboard?.writeText(`Check out my fan identity on Backstage! 💜 I'm a ${TYPE}. #Backstage #Fanverse`).catch(()=>{});setShared(true);}} className="tap" style={{ width:"100%",padding:"14px",borderRadius:14,background:shared?`${C.mint}22`:`linear-gradient(140deg,${C.accent},${C.pink})`,border:shared?`1.5px solid ${C.mint}`:"none",color:shared?C.mint:C.bg,fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:13.5,cursor:"pointer",boxShadow:shared?"none":`0 4px 22px ${C.accent}30`,transition:"all .3s" }}>{shared?"✓ Link Copied — Ready to Post!":"💜 Share My Fan Identity"}</button>

        <div style={{ marginTop:14,background:C.surfaceHi,border:`1px solid ${C.border}`,borderRadius:14,padding:13,textAlign:"center" }}>
          <p style={{ fontSize:11,color:C.textMid }}>🏆 Fan Resume is updated as you use the app. Log more shows, trades, and memories to level up your stats.</p>
        </div>
      </Screen>
    </div>
  );
}

function MapSnapshot({ onBack }) {
  const [shared, setShared] = useState(false);
  const CITY = "Dallas, TX";
  const ACTIVE_ZONE = HEAT_ZONES.find(z=>z.city===CITY)||HEAT_ZONES[0];

  return (
    <div style={{ height:"100%",display:"flex",flexDirection:"column",overflow:"hidden" }}>
      <div style={{ padding:"16px 20px",display:"flex",gap:10,alignItems:"center",flexShrink:0 }}>
        <button onClick={onBack} style={{ background:"none",border:"none",color:C.textMid,fontSize:22,cursor:"pointer" }}>←</button>
        <h2 style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:19 }}>Fan Map Snapshot 🗺️</h2>
      </div>
      <Screen style={{ padding:"0 20px calc(120px + env(safe-area-inset-bottom))" }}>
        {/* Map snapshot preview */}
        <div style={{ background:`linear-gradient(160deg,${C.bg},${C.surfaceMid})`,border:`1.5px solid ${ACTIVE_ZONE.color}44`,borderRadius:22,padding:20,marginBottom:18,position:"relative",overflow:"hidden",minHeight:240,animation:"shareGlow 4s ease infinite" }}>
          <p style={{ fontSize:9,color:ACTIVE_ZONE.color,fontFamily:"'Epilogue',sans-serif",fontWeight:700,textTransform:"uppercase",letterSpacing:"0.14em",marginBottom:12 }}>BACKSTAGE · FANVERSE MAP</p>
          {/* Mini map art */}
          <div style={{ position:"relative",height:150,background:C.surfaceHi,borderRadius:16,border:`1.5px solid ${C.border}`,overflow:"hidden",marginBottom:14 }}>
            <div style={{ position:"absolute",inset:0,background:`radial-gradient(ellipse at 52% 62%,${C.pink}30,transparent 55%), radial-gradient(ellipse at 17% 55%,${C.mint}20,transparent 45%), radial-gradient(ellipse at 73% 34%,${C.silver}20,transparent 40%)` }} />
            {HEAT_ZONES.filter(z=>z.active).map((z,i)=>(
              <div key={i} style={{ position:"absolute",left:`${z.x}%`,top:`${z.y}%`,transform:"translate(-50%,-50%)" }}>
                <div style={{ width:z.city===CITY?18:10,height:z.city===CITY?18:10,borderRadius:"50%",background:z.color,boxShadow:`0 0 ${z.city===CITY?12:6}px ${z.color}88`,position:"relative" }}>
                  {z.city===CITY&&<div style={{ position:"absolute",inset:-6,borderRadius:"50%",border:`2px solid ${z.color}`,animation:"inviteRing 2s ease infinite" }} />}
                </div>
              </div>
            ))}
          </div>
          {/* City callout */}
          <div style={{ display:"flex",gap:12,alignItems:"center" }}>
            <div style={{ width:42,height:42,borderRadius:12,background:`${ACTIVE_ZONE.color}22`,border:`1.5px solid ${ACTIVE_ZONE.color}55`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:20,flexShrink:0 }}>📍</div>
            <div>
              <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:16,color:ACTIVE_ZONE.color }}>{CITY}</p>
              <p style={{ fontSize:12,color:C.textMid }}>{ACTIVE_ZONE.fans} preview · {ACTIVE_ZONE.concerts[0]||"No shows this month"}</p>
            </div>
          </div>
          <div style={{ position:"absolute",bottom:14,right:16 }}>
            <p style={{ fontSize:9,color:C.textDim,fontFamily:"'Epilogue',sans-serif",fontWeight:600 }}>backstagefanverse.com/map</p>
          </div>
        </div>

        <button onClick={()=>{navigator.clipboard?.writeText(`I'm part of the ${CITY} fan community on Backstage! ${ACTIVE_ZONE.fans} fans active here 🗺️💜 #Backstage #Fanverse`).catch(()=>{});setShared(true);}} className="tap" style={{ width:"100%",padding:"14px",borderRadius:14,background:shared?`${C.mint}22`:`linear-gradient(140deg,${C.mint},${C.accent})`,border:shared?`1.5px solid ${C.mint}`:"none",color:shared?C.mint:C.bg,fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:13.5,cursor:"pointer",boxShadow:shared?"none":`0 4px 22px ${C.mint}30`,transition:"all .3s" }}>{shared?"✓ Caption Copied!":"🗺️ Share My Map Snapshot"}</button>
      </Screen>
    </div>
  );
}

// ─── FANVERSE HEAT MAP (Enhanced CommunityTab map section) ────────────────────
function FanverseHeatMap({ go }) {
  const [selectedZone, setSelectedZone] = useState(null);
  const [showAll, setShowAll] = useState(false);

  const totalFans = HEAT_ZONES.reduce((s,z)=>s+z.fans,0);

  return (
    <div>
      {/* Live header */}
      <div style={{ display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10 }}>
        <div style={{ display:"flex",gap:6,alignItems:"center" }}>
          <div style={{ width:8,height:8,borderRadius:"50%",background:C.mint,animation:"pulse 1.5s infinite" }} />
          <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:11,color:C.mint }}>LIVE · {totalFans.toLocaleString()} fans across the Fanverse</p>
        </div>
        <Pill color={C.accent} xs>{HEAT_ZONES.filter(z=>z.pulse==="spike").length} Spikes 🔥</Pill>
      </div>

      {/* SVG-style map container */}
      <div style={{ position:"relative",height:180,background:`linear-gradient(180deg,${C.surfaceHi},${C.surface})`,borderRadius:20,border:`1.5px solid ${C.borderHi}`,overflow:"hidden",marginBottom:14 }}>
        {/* Base gradient heat */}
        <div style={{ position:"absolute",inset:0,background:`radial-gradient(ellipse at 52% 62%,${C.pink}22,transparent 40%), radial-gradient(ellipse at 17% 55%,${C.mint}16,transparent 38%), radial-gradient(ellipse at 73% 34%,${C.silver}14,transparent 36%), radial-gradient(ellipse at 57% 38%,${C.accent}14,transparent 35%)`,pointerEvents:"none" }} />
        {/* Grid lines (subtle) */}
        <svg style={{ position:"absolute",inset:0,width:"100%",height:"100%",opacity:0.08 }}>
          {[25,50,75].map(x=><line key={x} x1={`${x}%`} y1="0" x2={`${x}%`} y2="100%" stroke={C.accent} strokeWidth="1" />)}
          {[33,66].map(y=><line key={y} x1="0" y1={`${y}%`} x2="100%" y2={`${y}%`} stroke={C.accent} strokeWidth="1" />)}
        </svg>
        {/* Heat zones */}
        {HEAT_ZONES.map((z,i)=>(
          <div key={i} onClick={()=>setSelectedZone(selectedZone?.city===z.city?null:z)} style={{ position:"absolute",left:`${z.x}%`,top:`${z.y}%`,transform:"translate(-50%,-50%)",cursor:"pointer",zIndex:2 }}>
            {/* Pulse ring */}
            <div style={{ position:"absolute",inset:-(z.pulse==="spike"?14:z.pulse==="high"?10:7),borderRadius:"50%",border:`1.5px solid ${z.color}`,animation:z.pulse==="spike"||z.pulse==="high"?"inviteRing 2s ease infinite":"none",opacity:0.5 }} />
            {/* Core dot */}
            <div style={{ width:z.pulse==="spike"?20:z.pulse==="high"?15:z.pulse==="active"?11:8,height:z.pulse==="spike"?20:z.pulse==="high"?15:z.pulse==="active"?11:8,borderRadius:"50%",background:z.color,boxShadow:`0 0 ${z.pulse==="spike"?18:10}px ${z.color}99`,transition:"all .3s",border:`2px solid ${z.pulse==="spike"?C.white:z.color}55`,animation:z.pulse==="spike"?"heatBeat 1.8s ease infinite":"none" }} />
            {/* City label for spike/high */}
            {(z.pulse==="spike"||z.pulse==="high")&&(
              <div style={{ position:"absolute",top:"100%",left:"50%",transform:"translateX(-50%)",marginTop:6,whiteSpace:"nowrap",background:`${C.bg}ee`,borderRadius:8,padding:"2px 7px",border:`1px solid ${z.color}44` }}>
                <p style={{ fontSize:8.5,fontFamily:"'Epilogue',sans-serif",fontWeight:700,color:z.color }}>{z.city.split(",")[0]}</p>
              </div>
            )}
          </div>
        ))}
        {/* Legend */}
        <div style={{ position:"absolute",top:10,left:10,display:"flex",flexDirection:"column",gap:4 }}>
          {[["🔥 Spike",C.pink],[" ⚡ High",C.accent],["💜 Active",C.mint]].map(([label,color])=>(
            <div key={label} style={{ display:"flex",gap:5,alignItems:"center" }}>
              <div style={{ width:7,height:7,borderRadius:"50%",background:color }} />
              <p style={{ fontSize:8,color:C.textMid,fontFamily:"'Epilogue',sans-serif",fontWeight:600 }}>{label}</p>
            </div>
          ))}
        </div>
      </div>

      {/* Selected zone detail */}
      {selectedZone && (
        <div style={{ background:`linear-gradient(140deg,${selectedZone.color}14,${selectedZone.color}06)`,border:`1.5px solid ${selectedZone.color}50`,borderRadius:18,padding:16,marginBottom:14,animation:"viralPop .2s ease" }}>
          <div style={{ display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10 }}>
            <div><p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:16,color:selectedZone.color }}>{selectedZone.city}</p><p style={{ fontSize:11.5,color:C.textMid }}>{selectedZone.fans} preview · {selectedZone.concerts.length>0?"Show week":"No shows soon"}</p></div>
            <Pill color={selectedZone.color} active small>{selectedZone.pulse==="spike"?"🔥 Spike":selectedZone.pulse==="high"?"⚡ High":"💜 Active"}</Pill>
          </div>
          {selectedZone.concerts.length>0&&(
            <div style={{ background:`${selectedZone.color}0a`,borderRadius:11,padding:"8px 12px",marginBottom:12 }}>
              {selectedZone.concerts.map((c,i)=><p key={i} style={{ fontSize:12,color:selectedZone.color,fontFamily:"'Epilogue',sans-serif",fontWeight:600 }}>🎤 {c}</p>)}
            </div>
          )}
          <button onClick={()=>go("concerts")} style={{ width:"100%",padding:"10px",borderRadius:11,background:selectedZone.color,border:"none",color:C.bg,fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:12,cursor:"pointer" }}>Join fans here →</button>
        </div>
      )}

      {/* City list */}
      <div style={{ display:"flex",flexDirection:"column",gap:8 }}>
        {HEAT_ZONES.slice(0,showAll?HEAT_ZONES.length:4).map(z=>(
          <div key={z.city} onClick={()=>setSelectedZone(selectedZone?.city===z.city?null:z)} className="tap" style={{ background:selectedZone?.city===z.city?`${z.color}12`:C.surface,border:`1.5px solid ${selectedZone?.city===z.city?z.color:C.border}`,borderRadius:14,padding:"11px 14px",cursor:"pointer",display:"flex",gap:12,alignItems:"center",transition:"all .2s" }}>
            <div style={{ width:10,height:10,borderRadius:"50%",background:z.color,flexShrink:0,animation:z.pulse==="spike"?"heatBeat 1.8s ease infinite":"none" }} />
            <div style={{ flex:1 }}>
              <div style={{ display:"flex",gap:7,alignItems:"center",marginBottom:2 }}><p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:13 }}>{z.city}</p>{z.concerts.length>0&&<Pill color={z.color} xs>Show</Pill>}</div>
              <p style={{ fontSize:10.5,color:C.textMid }}>{z.fans} preview signal</p>
            </div>
            <div style={{ textAlign:"right" }}><p style={{ fontSize:11,color:z.color,fontFamily:"'Epilogue',sans-serif",fontWeight:700 }}>{z.pulse==="spike"?"🔥":z.pulse==="high"?"⚡":"💜"}</p></div>
          </div>
        ))}
      </div>
      {!showAll&&HEAT_ZONES.length>4&&(
        <button onClick={()=>setShowAll(true)} style={{ width:"100%",marginTop:8,padding:"10px",background:"transparent",border:`1px solid ${C.border}`,borderRadius:12,color:C.textMid,fontFamily:"'Epilogue',sans-serif",fontWeight:600,fontSize:12,cursor:"pointer" }}>Show all {HEAT_ZONES.length} cities →</button>
      )}
    </div>
  );
}


// ─── VIRAL TICKER (UPGRADED) ──────────────────────────────────────────────────
function ViralTicker() {
  const items = [
    "🎤 BTS Dallas · Apr 30 — concert week",
    "🃏 Karina UR — trade matching preview",
    "✨ aespa Drama Tour LA — Jun 2",
    "💜 SKZ Chicago · May 14 — upcoming",
    "👯 Bring your crew — find fans before the show",
    "🎁 Concert Capsule — save your night with fans",
    "✦ Backstage · The fan memory app",
  ];
  const doubled = [...items, ...items];
  return (
    <div style={{
      position: "relative",
      background: `linear-gradient(90deg, ${C.accent}10, ${C.pink}08, ${C.accent}10)`,
      border: `1px solid ${C.accent}22`,
      borderRadius: 14,
      padding: "9px 0",
      marginBottom: 28,
      overflow: "hidden",
    }}>
      {/* fade edges */}
      <div style={{ position:"absolute",left:0,top:0,bottom:0,width:40,background:`linear-gradient(90deg,${C.bg},transparent)`,zIndex:2,pointerEvents:"none" }} />
      <div style={{ position:"absolute",right:0,top:0,bottom:0,width:40,background:`linear-gradient(270deg,${C.bg},transparent)`,zIndex:2,pointerEvents:"none" }} />
      <div style={{ display:"flex", gap:32, animation:"tickerScroll 22s linear infinite", willChange:"transform", width:"max-content" }}>
        {doubled.map((item, i) => (
          <p key={i} style={{ fontSize:11.5, color:C.silver, whiteSpace:"nowrap", flexShrink:0, paddingLeft:i===0?16:0, letterSpacing:"0.01em" }}>{item}</p>
        ))}
      </div>
    </div>
  );
}

