  const EMOJIS = ["🎤","✨","🃏","💜","🌙","⭐","🦋","🎧"];
  const BANNER_TEXTS = ["currently in my concert era","collecting chaos beautifully","ult era loading","bias wrecked daily","here for the music & the fandom"];
